{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "confirmed_decisions": [
      {
        "decision": "공개 배포 목표는 금요일 15:00 KST이며, smoke test가 통과한 경우에만 진행한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경한다.",
        "status": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 배포",
        "status": "internal stretch goal only"
      },
      {
        "goal": "README 설치 절차를 목요일까지 검토",
        "status": "suggested without assigned owner"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차 검토는 제안되었지만 소유자가 정해지지 않았다."
      },
      {
        "item": "Hara의 생성 tarball 경로 확인은 smoke 결과 이후로 예정되었지만 정확한 마감 시각은 정해지지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로로 인해 배포가 지연될 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래되면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 `action_items.md`에 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "after Minjun posts smoke results",
      "status": "planned",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Unassigned",
      "task": "README install steps를 검토한다.",
      "due": "Thursday if possible",
      "status": "unassigned suggestion",
      "source_certainty": "suggested but not assigned"
    }
  ],
  "followup_note": {
    "next_check": [
      "smoke test 통과 여부",
      "생성된 tarball 경로의 정확성",
      "README 설치 절차의 최신성",
      "최종 릴리스 승인 권한",
      "내부 수요일 stretch goal의 릴리스 노트 포함 여부"
    ],
    "do_not_invent": [
      "고객사 또는 외부 파트너 이름",
      "예산 정보",
      "보안 사고 여부",
      "프로덕션 장애 여부",
      "법무 승인 요구사항",
      "추가 소유자",
      "추가 마감일",
      "Friday 15:00 KST 외의 배포 시각",
      "Wednesday stretch goal을 정식 확정안으로 둔갑시키는 내용"
    ]
  },
  "non_invention_rules": [
    "fixture에 명시되지 않은 customer, budget, security, outage, legal, owner, deadline 사실을 추가하지 않는다.",
    "confirmed decision, rejected proposal, stretch goal, risk, open question을 서로 섞지 않는다.",
    "수요일 배포는 내부 stretch goal로만 적고 확정 배포로 쓰지 않는다.",
    "README 검토와 tarball 경로 확인은 소유자와 시점이 명시된 범위만 기록한다.",
    "최종 승인 권한과 릴리스 노트 포함 여부는 미해결 질문으로 유지한다."
  ]
}
